    make_wrapped_arith_op,
)
from pandas.core.indexes.numeric import Int64Index
from pandas.core.ops import get_op_result_name
from pandas.core.tools.timedeltas import to_timedelta

from pandas.tseries.frequencies import DateOffset, to_offset
from pandas.tseries.offsets import Tick

_index_doc_kwargs = dict(ibase._index_doc_kwargs)


def _join_i8_wrapper(join_func, with_indexers: bool = True):
    """
    Create the join wrapper methods.
    """

    @staticmethod  # type: ignore
    def wrapper(lhs, rhs):
        if isinstance(lhs, (np.ndarray, ABCIndex, ABCSeries, DatetimeLikeArrayMixin)):
            lhs = lhs.view("i8")
        if isinstance(rhs, (np.ndarray, ABCIndex, ABCSeries, DatetimeLikeArrayMixin)):
            rhs = rhs.view("i8")

        result_values = join_func(lhs, rhs)
        if with_indexers:
            # dtype should be timedelta64[ns] for TimedeltaIndex
            #  and datetime64[ns] for DatetimeIndex
            dtype_base = lhs.dtype.base

            joined_idx, lhs_indexer, rhs_indexer = result_values
            joined_idx = joined_idx.view(dtype_base)
            return joined_idx, lhs_indexer, rhs_indexer
        return result_values

    return wrapper


def _make_wrapped_arith_op_with_freq(operation_name: str):
    """
    Dispatch the operation to the underlying ExtensionArray, and infer
    the appropriate frequency for the result.
    """
    method_impl = make_wrapped_arith_op(operation_name)

    def wrapper_func(self, other):
        op_result = method_impl(self, other)
        if op_result is NotImplemented:
            return NotImplemented

        result_freq = self._get_addsub_freq(other)
        op_result._freq = result_freq
        return op_result

    wrapper_func.__name__ = operation_name
    return wrapper_func


@inherit_names(
    ["inferred_freq", "_isnan", "_resolution", "resolution"],
    DatetimeLikeArrayMixin,
    cache=True,
)
@inherit_names(
    ["mean", "asi8", "_box_func"], DatetimeLikeArrayMixin,
)
class DatetimeIndexOpsMixin(ExtensionIndex):
    """
    Common ops mixin to support a unified interface datetimelike Index.
    """

    _data: Union[DatetimeArray, TimedeltaArray, PeriodArray]
    freq: Optional[DateOffset]
    freqstr: Optional[str]
    _resolution: int
    _bool_ops: List[str] = []
    _field_ops: List[str] = []

    hasnans = cache_readonly(DatetimeLikeArrayMixin._hasnans.fget)  # type: ignore
    _hasnans = hasnans  # for index / array -agnostic code

    @property
    def is_all_dates(self) -> bool:
        return True

    # ------------------------------------------------------------------------
    # Abstract data attributes

    @property
    def values(self):
        # Note: PeriodArray overrides this to return an ndarray of objects.
        return self._data._data

    def __array_wrap__(self, result, context=None):
        """
        Gets called after a ufunc.
        """
        result = lib.item_from_zerodim(result)
        if is_bool_dtype(result) or lib.is_scalar(result):
            return result

        attr_dict = self._get_attributes_dict()
        if not is_period_dtype(self) and attr_dict["freq"]:
            # no need to infer if freq is None
            attr_dict["freq"] = "infer"
        return Index(result, **attr_dict)

    # ------------------------------------------------------------------------

    def equals(self, other) -> bool:
        """
        Determines if two Index objects contain the same elements.
        """
        if self.is_(other):
            return True

        if not isinstance(other, ABCIndexClass):
            return False
        elif not isinstance(other, type(self)):
            try:
                other = type(self)(other)
            except (ValueError, TypeError, OverflowError):
                # e.g.
                #  ValueError -> cannot parse str entry, or OutOfBoundsDatetime
                #  TypeError  -> trying to convert IntervalIndex to DatetimeIndex
                #  OverflowError -> Index([very_large_timedeltas])
                return False

        if not is_dtype_equal(self.dtype, other.dtype):
            # have different timezone
            return False

        return np.array_equal(self.asi8, other.asi8)

    @Appender(Index.__contains__.__doc__)
    def __contains__(self, key: Any) -> bool:
        hash(key)
        try:
            location = self.get_loc(key)
        except (KeyError, TypeError, ValueError):
            return False
        return bool(
            is_scalar(location) or isinstance(location, slice) or (is_list_like(location) and len(location))
        )

    def sort_values(self, return_indexer=False, ascending=True):
        """
        Return sorted copy of Index.
        """
        if return_indexer:
            sort_indices = self.argsort()
            if not ascending:
                sort_indices = sort_indices[::-1]
            sorted_idx = self.take(sort_indices)
            return sorted_idx, sort_indices
        else:
            # NB: using asi8 instead of _data matters in numpy 1.18
            #  because the treatment of NaT has been changed to put NaT last
            #  instead of first.
            sorted_vals = np.sort(self.asi8)

            frequency = self.freq
            if frequency is not None and not is_period_dtype(self):
                if frequency.n > 0 and not ascending:
                    frequency = frequency * -1
                elif frequency.n < 0 and ascending:
                    frequency = frequency * -1

            if not ascending:
                sorted_vals = sorted_vals[::-1]

            array_obj = type(self._data)._simple_new(
                sorted_vals, dtype=self.dtype, freq=frequency
            )
            return type(self)._simple_new(array_obj, name=self.name)

    @Appender(_index_shared_docs["take"] % _index_doc_kwargs)
    def take(self, indices, axis=0, allow_fill=True, fill_value=None, **kwargs):
        nv.validate_take(tuple(), kwargs)
        indices = ensure_int64(indices)

        potential_slice = lib.maybe_indices_to_slice(indices, len(self))
        if isinstance(potential_slice, slice):
            return self[potential_slice]

        return ExtensionIndex.take(
            self, indices, axis, allow_fill, fill_value, **kwargs
        )

    @doc(IndexOpsMixin.searchsorted, klass="Datetime-like Index")
    def searchsorted(self, value, side="left", sorter=None):
        if isinstance(value, str):
            raise TypeError(
                "searchsorted requires compatible dtype or scalar, "
                f"not {type(value).__name__}"
            )
        if isinstance(value, Index):
            value = value._data

        return self._data.searchsorted(value, side=side, sorter=sorter)

    _can_hold_na = True

    _na_value = NaT
    """The expected NA value to use with this index."""

    def _convert_tolerance(self, tolerance, target):
        tolerance = np.asarray(to_timedelta(tolerance).to_numpy())

        if target.size != tolerance.size and tolerance.size > 1:
            raise ValueError("list-like tolerance size must match target index size")
        return tolerance

    def tolist(self) -> List:
        """
        Return a list of the underlying data.
        """
        return list(self.astype(object))

    def min(self, axis=None, skipna=True, *args, **kwargs):
        """
        Return the minimum value of the Index or minimum along
        an axis.

        See Also
        --------
        numpy.ndarray.min
        Series.min : Return the minimum value in a Series.
        """
        nv.validate_min(args, kwargs)
        nv.validate_minmax_axis(axis)

        if not len(self):
            return self._na_value

        int_values = self.asi8
        try:
            # quick check
            if len(int_values) and self.is_monotonic:
                if int_values[0] != iNaT:
                    return self._box_func(int_values[0])

            if self.hasnans:
                if skipna:
                    min_timestamp = self[~self._isnan].asi8.min()
                else:
                    return self._na_value
            else:
                min_timestamp = int_values.min()
            return self._box_func(min_timestamp)
        except ValueError:
            return self._na_value

    def argmin(self, axis=None, skipna=True, *args, **kwargs):
        """
        Returns the indices of the minimum values along an axis.

        See `numpy.ndarray.argmin` for more information on the
        `axis` parameter.

        See Also
        --------
        numpy.ndarray.argmin
        """
        nv.validate_argmin(args, kwargs)
        nv.validate_minmax_axis(axis)

        int_values = self.asi8
        if self.hasnans:
            nan_mask = self._isnan
            if nan_mask.all() or not skipna:
                return -1
            int_values = int_values.copy()
            int_values[nan_mask] = np.iinfo("int64").max
        return int_values.argmin()

    def max(self, axis=None, skipna=True, *args, **kwargs):
        """
        Return the maximum value of the Index or maximum along
        an axis.

        See Also
        --------
        numpy.ndarray.max
        Series.max : Return the maximum value in a Series.
        """
        nv.validate_max(args, kwargs)
        nv.validate_minmax_axis(axis)

        if not len(self):
            return self._na_value

        int_values = self.asi8
        try:
            # quick check
            if len(int_values) and self.is_monotonic:
                if int_values[-1] != iNaT:
                    return self._box_func(int_values[-1])

            if self.hasnans:
                if skipna:
                    max_timestamp = self[~self._isnan].asi8.max()
                else:
                    return self._na_value
            else:
                max_timestamp = int_values.max()
            return self._box_func(max_timestamp)
        except ValueError:
            return self._na_value

    def argmax(self, axis=None, skipna=True, *args, **kwargs):
        """
        Returns the indices of the maximum values along an axis.

        See `numpy.ndarray.argmax` for more information on the
        `axis` parameter.

        See Also
        --------
        numpy.ndarray.argmax
        """
        nv.validate_argmax(args, kwargs)
        nv.validate_minmax_axis(axis)

        int_values = self.asi8
        if self.hasnans:
            nan_mask = self._isnan
            if nan_mask.all() or not skipna:
                return -1
            int_values = int_values.copy()
            int_values[nan_mask] = 0
        return int_values.argmax()

    # --------------------------------------------------------------------
    # Rendering Methods

    def _format_with_header(self, header, na_rep="NaT", **kwargs):
        return header + list(self._format_native_types(na_rep, **kwargs))

    @property
    def _formatter_func(self):
        raise AbstractMethodError(self)

    def _format_attrs(self):
        """
        Return a list of tuples of the (attr,formatted_value).
        """
        attribute_list = super()._format_attrs()
        for attr_name in self._attributes:
            if attr_name == "freq":
                frequency = self.freqstr
                if frequency is not None:
                    frequency = repr(frequency)
                attribute_list.append(("freq", frequency))
        return attribute_list

    # --------------------------------------------------------------------
    # Indexing Methods

    def _validate_partial_date_slice(self, reso: str):
        raise NotImplementedError

    def _parsed_string_to_bounds(self, reso: str, parsed: datetime):
        raise NotImplementedError

